var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"INTERN_MAIN_NPC_QM","text":{"KOREA":"우웅… 너무 시끄러워…….","JPN":"うーん……うるさーい……","ENG":"Mmmgh... so noisy...","TWN":"呃嗯……太吵了……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_MAIN_NPC_QM","text":{"KOREA":"무슨 소리지…? 아직 컴컴해… 더 자고 싶은데…….","JPN":"何の音……？　まだ暗いよ……もっと寝てたいのに……","ENG":"What's that sound...? It's still dark... I want to sleep a little longer...","TWN":"什麼聲音……？天還很黑呢……我還想再睡一會兒……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"쓰읍……!!","JPN":"じゅる……！！","ENG":"*Slurp…!!*","TWN":"嘶……！！"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"헙!? 침 잔뜩 흘려버렸다!","JPN":"ハッ！？　大量のよだれが！","ENG":"Huh?! I drooled all over myself!","TWN":"哇？！流了好多口水！"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"아, 아무도 못 봤겠지?","JPN":"だ、誰にも見られてないよね？","ENG":"Ah, no one saw that, right?","TWN":"啊，應該沒人看見吧？"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L17_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"우웅, 이런 멍청한 얼굴… 미나 선배가 봤다간, 못난이 후배라고 생각할 거야…….","JPN":"うーん、こんなだらしない顔……ミナ先輩に見られたらブサイクな後輩だって思われちゃう……","ENG":"Ugh, I looked like such a mess... if Mina saw me like that, she'd totally think I'm hopeless...","TWN":"嗚嗚，這麼蠢的表情……要是被米娜前輩看到了，會覺得我是個笨蛋的……"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"어, 어라? 그런데 여긴 어디지? 무슨 영화관 같은데……?","JPN":"あ、あれ？　ここどこ？　なんか映画館っぽいけど……？","ENG":"H-Huh? Wait, where am I? This looks like a movie theater...?","TWN":"呃、咦？這裡是哪裡？好像是電影院……？"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"아하, 그렇구나! 어쩌면 영화를 보다가 깜빡 잠들어 버렸을지도……!?","JPN":"あっ、そうか！　もしかしたら映画見てる途中で寝落ちしちゃったのかも……！？","ENG":"Aha, that's it! Maybe I dozed off while watching a movie...?!","TWN":"啊哈，是這樣啊！說不定是看電影的時候不小心睡著了吧……？！"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"무슨 영화였더라? 뭔가 엄청나게 거대한 우주선이 등장하는 SF 영화였던 것 같은데……?","JPN":"どういう映画だっけ？　なんかもの凄く大きな宇宙船が出てくる、SF映画だった気がするんだけど……？","ENG":"What kind of movie was it again? I vaguely remember some massive spaceship... must've been sci-fi?","TWN":"是什麼電影來著？好像是出現了非常巨大的太空船的科幻電影……？"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"하아암~ 재미없는 영화였나 봐. 내용이 하나도 기억 안 나는 걸~","JPN":"ふあ～、きっとつまんない映画だったんだ。内容が全然思い出せないもん～","ENG":"Yaaawn! Must've been boring. I don't remember a single thing about it!","TWN":"哈欠～看來是部無聊的電影，我一點內容都記不住～"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"이상해. 왜 아무도 없지?","JPN":"おかしいな。どうして誰もいないの？","ENG":"This is strange. Where is everyone?","TWN":"奇怪，為什麼沒人？"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"영화도 끝났는데 손님을 방치해 두다니… 무슨 극장이 이렇담?","JPN":"映画も終わったのに、客を放置するなんて……変な劇場！","ENG":"The movie's over, but they just left a guest sitting here? What kind of theater does that?","TWN":"電影都結束了還把客人晾在一邊……這是什麼電影院啊？"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그래, 출구! 우선 출구부터 찾는 거야!","JPN":"そうだ、出口！　まずは出口を探そう！","ENG":"Okay, the exit! First thing's first. I'll find the exit!","TWN":"對，出口！首先要找到出口！"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"허억, 허억……!","JPN":"はあ……はあ……！","ENG":"*Huff* *Huff…!*","TWN":"呵、呵……！"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"어두컴컴해서 잘 몰랐는데… 이 극장 엄청 넓잖아? 뛰어도, 뛰어도 끝이 없어!","JPN":"暗くてわからなかったけど、この劇場めちゃくちゃ広くない？　走っても走っても終わりが見えない！","ENG":"It was hard to tell in the dark, but... this theater is huge! I keep running and running, but there's no end in sight!","TWN":"因為太黑了所以沒注意到……這個劇場好大啊！怎麼跑都跑不到盡頭！"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"아니, 잠깐… 어쩐지 같은 곳을 뺑뺑 돌고 있다는 느낌이…….","JPN":"うん？　ちょっと待って、なんか同じところをぐるぐる回ってるような……","ENG":"Wait... hold on. It feels like I've been running in circles...","TWN":"不，等等……總覺得好像在同一個地方兜圈子……"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"대체 여긴 어디지……?","JPN":"ここっていったいどこなの……？","ENG":"Just where am I...?","TWN":"這裡到底是哪裡……？"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"저기요! 거기 누구 없나요? 여기 사람 있어요!","JPN":"すみません！　誰かいませんか？　まだ人がいるんですけど！","ENG":"Hello! Is anyone out there? There's someone here!","TWN":"喂！有沒有人啊？這裡有人！"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"미나 선배! 어디 있어요! 펠리세트, 라이카! 저 여기에 있다고요!","JPN":"ミナ先輩！　どこですか？　フェリセット、ライカ！　私ここです！","ENG":"Mina! Where are you? Félicette, Laika! I'm right here!","TWN":"米娜前輩！你在哪裡！費莉塞特，萊卡！我在這裡啊！"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"다들… 다들 있으면, 대답 좀 해봐요!","JPN":"みんな！　いたら返事をしてください！","ENG":"Everyone... if you're out there, please say something!","TWN":"大家……大家在的話，請回答我一下！"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"소용없어요, 노엘 라이트.","JPN":"無駄ですよ、ノエル・ライト。","ENG":"It's pointless, Noelle Wright.","TWN":"沒用的，洛艾兒·萊特。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"그들은 이곳에 초대받은 관객이 아니니까요.","JPN":"彼女たちは招かれた観客ではありませんから。","ENG":"They are not guests invited to this place.","TWN":"他們並不是被邀請的觀眾。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"이 목소리는……?","JPN":"この声は……？","ENG":"Whose voice is that...?","TWN":"這聲音是……？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무대란, 관객이 존재하기에 비로소 그 의미를 갖는 법.","JPN":"舞台とは、観客がいて初めて意味を持つもの。","ENG":"A stage only holds meaning when there is an audience.","TWN":"舞台，只有在觀眾存在時才有意義。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"단 한 사람이라도 관객이 존재한다면, 그곳이 어디든 무대가 될 수 있습니다.","JPN":"たった1人でも観客が存在するなら、そこがどこだろうと舞台になり得ます。","ENG":"If even one person is watching, then anywhere can become a stage.","TWN":"只要有一個觀眾存在，哪裡都可以成為舞台。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"설령, 그 무대가 차디찬 <color=#ffd34c>거울</color> 속 세계라고 할지라도 말이죠.","JPN":"たとえ、その舞台が凍えるような<color=#ffd34c>鏡</color>の中の世界だとしても。","ENG":"Even if that stage exists within a cold world reflected in a <color=#ffd34c>mirror</color>.","TWN":"即便那個舞台是個<color=#ffd34c>鏡子</color>中的冰冷世界。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"거울…… ","JPN":"鏡……","ENG":"A mirror...","TWN":"鏡子……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"흣!?","JPN":"っ！？","ENG":"Heut?!","TWN":"唔？！"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はぁ、はぁ、はぁ……！","ENG":"*Huff* *Huff* *Huff*","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그래, 기억났어……!","JPN":"思い出した……！","ENG":"That's right, I remember now...!","TWN":"對，我想起來了……！"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그때… 당신이 우리 마을에 나타나서… 교회에 있던 사람들을 모두…….","JPN":"あの時……あなたが村に現れて……教会にいた人たちをみんな……","ENG":"Back then... you came to our village... And you were the one who did that to everyone in the church...","TWN":"那時……你出現在我們村子裡……把教堂裡的人全都……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그리고 우리 부모님을……!","JPN":"お母さんと……お父さんまで……！","ENG":"And even my parents...!","TWN":"還有我的父母……！"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"스완! 대체 무슨 속셈이죠?","JPN":"スワン！　いったい何のつもりですか？","ENG":"Swan! What exactly are you up to?","TWN":"史旺！你到底想幹什麼？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"당신이 절 이 극장에 가둔 건가요?","JPN":"あなたが私をこの劇場に閉じ込めたんですか？","ENG":"Did you trap me in this theater?","TWN":"是你把我關在這個劇院裡的嗎？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"말씀드렸을 텐데요?","JPN":"言ったはずです。","ENG":"I told you already, didn't I?","TWN":"我應該說過吧？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신으로 하여금 저를 따르는 것 이외의 모든 선택지를 제거하겠다고.","JPN":"あなたから私に従う以外のすべての選択肢を除外すると。","ENG":"That I will remove all other options except following me.","TWN":"我會讓你別無選擇，只能跟隨我。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이곳은 당신이라는 관객 한 사람만을 위해, 존재하는 극장.","JPN":"ここはあなたという、たった1人の観客のために存在する劇場。","ENG":"This theater exists for one purpose alone... to host you, its only audience.","TWN":"這裡是只為你一位觀眾而存在的劇場。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>기억의 극장</color>에 오신 걸 환영합니다, 노엘 라이트.","JPN":"<color=#ffd34c>記憶の劇場</color>へようこそ、ノエル・ライト。","ENG":"Welcome to the <color=#ffd34c>Theater of Memory</color>, Noelle Wright.","TWN":"<color=#ffd34c>記憶劇場</color>歡迎你的到來，洛艾兒·萊特。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"기억의 극장이라고요……?","JPN":"記憶の劇場……？","ENG":"Theater of Memory...?","TWN":"記憶劇場……？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 극장은 저의 완전 기억 능력이 클리파 차원의 허수 에너지를 통해 재구성된 공간.","JPN":"この劇場は、私の完全記憶能力がクリファ次元の虚数エネルギーによって再構築された空間。","ENG":"This theater is a space where my perfect memory ability is reconstructed by the Qlipha Dimension's Imaginary Energy.","TWN":"這間劇場是我憑藉完全記憶能力，借助逆卡巴拉的虛數能量重新構建的空間。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"따라서 당신은 이곳에서 시간과 공간을 초월하여 제 <color=#ffd34c>각본</color>을 마주하게 될 겁니다.","JPN":"したがって、あなたにはここで時空を超えて、私の<color=#ffd34c>脚本</color>を楽しんでいただきます。","ENG":"Here, you'll witness my <color=#ffd34c>script</color> unfold, beyond the bounds of time and space.","TWN":"因此，你會在這超越時空的地方，面對我創造的<color=#ffd34c>劇本</color>。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 마음이 완전히 꺾일 때까지. 계속해서.","JPN":"あなたの心が完全に折れるまで。何度でも。","ENG":"Over and over, until your spirit is completely broken.","TWN":"直到你的心到最後徹底崩潰。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"각본……?","JPN":"脚本……？","ENG":"Script...?","TWN":"劇本……？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"여전히… 당신이 하는 말은 무슨 소리인지 하나도 모르겠어요……!","JPN":"相変わらず……あなたが何を言ってるのか、さっぱりわかりません……！","ENG":"I still... don't understand a word of what you're saying...!","TWN":"我真的……完全聽不懂你在說什麼啊……！"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"각본을 보여주겠다고요? 대체 그게 뭐죠?","JPN":"脚本を楽しむ？　もういい加減にして！","ENG":"You're going to show me a script? What even is that?","TWN":"給我看劇本？那到底是什麼啊？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"저한테 그런 상처를 줬으면서, 당신이 뭘 보여주든 제가 순순히 당신을 따를 것 같나요?","JPN":"あんなにひどいことをされて、何を見せられようがあなたに従うわけないでしょ！","ENG":"After everything you did to hurt me, do you really think I'll just go along with whatever you show me?","TWN":"你給我造成了那樣的傷害，你覺得我會乖乖聽你的嗎？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"당신에게 어떤 사정이 있든, 저는 당신을 동정하지 않을 거라고요! 절대로!","JPN":"あなたにどんな事情があっても、私はあなたに同情しません！　絶対に！","ENG":"Whatever your circumstances are, I'll never feel sorry for you! Never!","TWN":"不管你做什麼，我都不會同情你的！絕對不會！"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……동정?","JPN":"……同情？","ENG":"...Feel sorry?","TWN":"……同情？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 설마 악역인 저를 동정할 셈이었나요?","JPN":"ふふ、まさか悪役である私に同情するつもりだったのですか？","ENG":"Oh? Were you seriously thinking of feeling sorry for the villain?","TWN":"呵呵，難道你打算同情作為反派的我嗎？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"뭐가 우습죠?","JPN":"何がおかしいの！","ENG":"What's so amusing about that?","TWN":"你在笑什麼？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都在劇本之中。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 당신에게 이해나 동정 따위를 바라는 게 아닙니다.","JPN":"私はあなたに理解や同情などを望んでいるわけではありません。","ENG":"I'm not looking for your understanding or your sympathy.","TWN":"我並不指望你的理解或同情。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 바라는 건, 오직 당신 안에 잠들어 있는 <color=#ffd34c>세피라</color>…….","JPN":"私が望んでいるものはただ1つ、あなたの中に眠る<color=#ffd34c>セフィラ</color>……","ENG":"All I want... is the <color=#ffd34c>Sephira</color> sleeping inside you...","TWN":"我所期望的，只有沉睡在你體內的<color=#ffd34c>生命樹</color>……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이라는 껍데기로부터 그 신성을 끌어내기 위해서라면, 저는 무슨 짓이든 할 수 있어요.","JPN":"あなたという殻からその神聖を引き出すためなら、私はどんなことも厭わない。","ENG":"And if it means drawing that Divinity out from the shell you call a body, I'll do whatever it takes.","TWN":"為了從你這個軀殼中引出那份神性，我什麼都願意做。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 무대 위에 오른 이상, 같잖은 마음으로 악역을 동정하지 마세요.","JPN":"ですから舞台に上がった以上、生温い気持ちで悪役に同情なんてしないで。","ENG":"So now that you've stepped onto the stage, save your worthless sympathy for someone else.","TWN":"既然已經站上了舞台，就不要用可笑的心態去同情反派角色。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"진심으로 증오하고, 죽일 각오로 미워하는 겁니다, 노엘 라이트.","JPN":"本気で嫌い、殺す覚悟で憎むのです、ノエル・ライト。","ENG":"You must hate me with all your heart, Noelle Wright. Hate me with the resolve to kill.","TWN":"真心地憎恨我，並且抱著殺死我的決心去憎恨吧，洛艾兒·萊特。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"뭐, 그것조차도 그 연약한 자아가 이지를 잃지 않았을 경우의 이야기겠지만.","JPN":"まあ、それもその脆い自我が理性を失わなかった場合の話ですけど。","ENG":"Though, I suppose that only applies if your fragile self-awareness hasn't already shattered.","TWN":"雖然，那也只是在他那脆弱的自我沒有喪失理智之時的情況了。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그게 무슨……?","JPN":"どういう……？","ENG":"What do you mean...?","TWN":"那是什麼……？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"엇……?","JPN":"えっ……？","ENG":"Huh...?","TWN":"啊……？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FILM"},{"id":"L46_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"갑자기 스크린에서……?","JPN":"スクリーンから急に……？","ENG":"From the screen...? All of a sudden...?","TWN":"突然出現在螢幕上……？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"자, 그럼 각본을 고르도록 하겠습니다.","JPN":"さあ、それでは脚本を選びましょう。","ENG":"Now then, allow me to select the script.","TWN":"那麼，我來選擇劇本吧。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"첫 무대를 장식할 각본은… 역시 <color=#ffd34c>천사</color>와 관련된 이야기가 좋겠죠.","JPN":"初舞台を飾る脚本なら……やはり<color=#ffd34c>天使</color>にまつわる話がいいでしょうね。","ENG":"For the first act, a story involving an <color=#ffd34c>angel</color> should set the tone nicely.","TWN":"作為首場演出的劇本……果然還是和<color=#ffd34c>天使</color>有關的故事比較好。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 무척이나 오랫동안 천사를 쫓아왔으니까요.","JPN":"私はとても長い間、天使を追ってきましたから。","ENG":"After all, I've spent a very long time chasing an angel.","TWN":"我追逐天使已經很久了。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"……천사라고요?","JPN":"……天使？","ENG":"...An angel?","TWN":"……你說天使？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요, 노엘 라이트.","JPN":"そうです、ノエル・ライト。","ENG":"That's right, Noelle Wright.","TWN":"是的。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 이야기는 인간의 몸으로 신성에 다다르려 했던 어리석은 자들에 관한 이야기랍니다.","JPN":"この物語は人間の身でありながら、神聖に至ろうとした愚かな者たちの話です。","ENG":"This story is about the fools who tried to reach the Divinity through mortal flesh.","TWN":"這個故事，是關於那些愚蠢的人類試圖以凡人之軀接近神的故事。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 한편으로는… 당신과 연관되어 있기도 하죠.","JPN":"そして一方で……あなたにも繋がっています。","ENG":"And in a way... it's connected to you as well.","TWN":"還有另一方面……也與你有關。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금은 이미 사라져버린 어느 세계의 12월 24일…….","JPN":"今はもう滅亡してしまった、とある世界の12月24日……","ENG":"December 24th, in a world that has long since vanished...","TWN":"現在已經消失的，某個世界的12月24日……"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마치 세상에 모든 것을 집어삼킬 것 같은, 새하얀 눈으로 뒤덮인 화이트 크리스마스 이브.","JPN":"世界の全てを飲み込まんとするかのように、真っ白な雪で覆われたホワイトクリスマスイヴ。","ENG":"A white Christmas Eve, blanketed in snow so pure it looked as if it might swallow the world whole.","TWN":"仿佛要吞噬世間萬物一般，被潔白的雪覆蓋的白色聖誕前夜。"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……그날도, 클리포트 게임은 계속되고 있었답니다.","JPN":"……あの日も、クリフォトゲームの最中にありました。","ENG":"...And even on that day, the Qliphoth Game continued.","TWN":"……那天，逆卡巴拉遊戲仍在繼續。"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};